values.value:
[
  {
    "name": "newTask",
    "iconName": "standard:task",
    "type": "menu",
    "align": "left",
    "items": [
      {
        "name": "newTaskForm",
        "label": "New Task",
        "iconName": "standard:task",
        "action": {
          "type": "ldsForm",
          "params": {
            "title": "New Task",
            "columns": 1,
            "record": { "ObjectApiName": "Task", "WhatId": "{{{GEN.recordId}}}", "TaskSubtype": "Task" },
            "fields": [
              { "name": "WhatId", "hidden": true },
              { "name": "TaskSubtype", "hidden": true },
              { "name": "Subject", "required": true },
              { "name": "Status" },
              { "name": "Priority" },
              { "name": "ActivityDate" },
              { "name": "OwnerId" },
              { "name": "Description" }
            ],
            "next": { "type": "done", "params": { "type": "refresh" } }
          }
        }
      },
      {
        "name": "filterTasks",
        "label": "Tasks only",
        "iconName": "utility:filter",
        "action": {
          "type": "done",
          "params": { "type": "filter", "params": { "scope": "TypeName__c", "string": "Task" } }
        }
      },
      {
        "name": "filterAllFromTask",
        "label": "All activities",
        "iconName": "utility:filterList",
        "action": {
          "type": "done",
          "params": { "type": "filter", "params": { "scope": "ALL", "string": "" } }
        }
      }
    ]
  },
